from typing import Literal

from shiny import ui

ICON_NAMES = Literal[
    "arrow-clockwise",
    "arrow-counterclockwise",
    "bar-chart-fill",
    "box-arrow-up-right",
    "chevron-down",
    "chevron-left",
    "chevron-right",
    "download",
    "file-earmark-code",
    "funnel-fill",
    "graph-up",
    "grid-1x2-fill",
    "info-circle",
    "journal-code",
    "lightning-fill",
    "pencil-square",
    "pin-angle",
    "stars",
    "terminal-fill",
    "table",
    "three-dots",
    "x-lg",
]


def bs_icon(name: ICON_NAMES, cls: str = "") -> ui.HTML:
    """Get Bootstrap icon SVG by name."""
    if name not in BS_ICONS:
        raise ValueError(f"Unknown Bootstrap icon: {name}")
    svg = BS_ICONS[name]
    if cls:
        svg = svg.replace('class="', f'class="{cls} ', 1)
    return ui.HTML(svg)


